func MigrateSchematic(_ context.Context, old v53.Schematic) (Schematic, error) {
	data := old.Data
	s := Schematic{
		Key:             old.Key,
		Name:            old.Name,
		Snapshot:        old.Snapshot,
		Editable:        mapBool(data, "editable", true),
		FitViewOnResize: mapBool(data, "fitViewOnResize", false),
		Authority:       mapUint8(data, "authority", 1),
		Viewport:        extractViewport(data),
		Legend:          extractLegend(data),
		Nodes:           extractNodes(data),
	}
	props := mapRecord(data, "props")
	if props == nil {
		props = make(binary.MsgpackEncodedJSON)
	}
	s.Props = props
	return s, nil
}

func extractViewport(data map[string]any) spatial.Viewport {
	vp := spatial.Viewport{Zoom: 1}
	raw, ok := data["viewport"].(map[string]any)
	if !ok {
		return vp
	}
	vp.Zoom = mapFloat64(raw, "zoom", 1)
	if pos, ok := raw["position"].(map[string]any); ok {
		vp.Position.X = mapFloat64(pos, "x", 0)
		vp.Position.Y = mapFloat64(pos, "y", 0)
	}
	return vp
}

func extractLegend(data map[string]any) Legend {
	leg := Legend{
		Visible:  true,
		Position: spatial.StickyXY{X: 50, Y: 50},
		Colors:   make(map[string]string),
	}
	raw, ok := data["legend"].(map[string]any)
	if !ok {
		return leg
	}
	leg.Visible = mapBool(raw, "visible", true)
	if pos, ok := raw["position"].(map[string]any); ok {
		leg.Position.X = mapFloat64(pos, "x", 50)
		leg.Position.Y = mapFloat64(pos, "y", 50)
		if root, ok := pos["root"].(map[string]any); ok {
			leg.Position.Root.X = mapString(root, "x", "")
			leg.Position.Root.Y = mapString(root, "y", "")
		}
		if units, ok := pos["units"].(map[string]any); ok {
			leg.Position.Units.X = mapString(units, "x", "px")
			leg.Position.Units.Y = mapString(units, "y", "px")
		}
	}
	if colors, ok := raw["colors"].(map[string]any); ok {
		for k, v := range colors {
			if s, ok := v.(string); ok {
				leg.Colors[k] = s
			}
		}
	}
	return leg
}

func extractNodes(data map[string]any) []Node {
	rawNodes, ok := data["nodes"].([]any)
	if !ok {
		return nil
	}
	nodes := make([]Node, 0, len(rawNodes))
	for _, raw := range rawNodes {
		m, ok := raw.(map[string]any)
		if !ok {
			continue
		}
		n := Node{Key: mapString(m, "key", "")}
		if pos, ok := m["position"].(map[string]any); ok {
			n.Position.X = mapFloat64(pos, "x", 0)
			n.Position.Y = mapFloat64(pos, "y", 0)
		}
		n.Selected = mapBool(m, "selected", false)
		n.ZIndex = mapInt32(m, "zIndex", 0)
		n.Type = mapString(m, "type", "")
		nodes = append(nodes, n)
	}
	return nodes
}

